using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ServerTools
{
    [McpServerTool, Description("Returns the current server UTC time.")]
    public static string GetServerTime() =>
        DateTime.UtcNow.ToString("o");

    [McpServerTool, Description("Echoes the provided message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo")] string message) =>
        $"[{DateTime.UtcNow:HH:mm:ss}] {message}";
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ServerResources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            version = "1.0.0",
            environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            features = new { loggingEnabled = true, maxRetries = 3 }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "info://server", Name = "Server Info",
        MimeType = "application/json"),
     Description("Returns runtime server information.")]
    public static string GetServerInfo() =>
        JsonSerializer.Serialize(new
        {
            machineName = Environment.MachineName,
            osVersion = Environment.OSVersion.ToString(),
            dotnetVersion = Environment.Version.ToString(),
            startedAt = DateTime.UtcNow.ToString("o")
        }, new JsonSerializerOptions { WriteIndented = true });
}

